from scitokens.utils.keycache import KeyCache


def main():
    # TODO: Make this work
    keycache = KeyCache()
    res = keycache.list_keys()
    header = ["issuer", "expiration", "key_id", "keydata", "next_update"]
    print(f"{header[0]:<30} | {header[1]:<19} | {header[2]:<35} | {header[3]:<20} | {header[4]}")
    print("-" * 135)
    for record in res:
        print(f"{record[0]:<30} | {record[1]:<19} | {record[2]:<35} | {record[3][:20]:<20} | {record[4]}")

if __name__ == "__main__":
    main()
